"""Audio I/O and processing utilities.

Provides functions for loading, resampling, silence removal, chunking,
cross-fading, and format conversion. Used by ``OmniVoice.generate()`` during
inference post-processing.
"""

import numpy as np
import os
import sys
import torch
import torchaudio
from pydub import AudioSegment
from pydub.silence import detect_leading_silence, detect_nonsilent, split_on_silence


def _audio_debug_enabled() -> bool:
    return os.environ.get("OMNIVOICE_AUDIO_DEBUG", "1").strip().lower() not in {
        "0",
        "false",
        "no",
        "off",
    }


def _log_audio_debug(message: str) -> None:
    if _audio_debug_enabled():
        print(f"[OMNIVOICE_AUDIO] {message}", file=sys.stderr, flush=True)


def _tensor_duration_ms(audio: torch.Tensor, sampling_rate: int) -> float:
    if sampling_rate <= 0:
        return 0.0
    return (audio.shape[-1] * 1000.0) / sampling_rate


def _silence_threshold_db() -> float:
    """Return dB threshold for silence detection.

    More negative values preserve quiet breaths and only treat near-dead-air as silence.
    """
    raw = os.environ.get("OMNIVOICE_SILENCE_DB", "-60")
    try:
        value = float(raw)
    except (TypeError, ValueError):
        value = -60.0

    # Keep in a sane range for dBFS-based silence detection.
    return max(-90.0, min(-10.0, value))


def _middle_silence_stats(
    audio: AudioSegment,
    silence_threshold: float,
) -> tuple[int, int, int]:
    """Return middle-silence stats (excluding leading/trailing silence).

    Returns:
        (middle_silence_ms, max_middle_gap_ms, middle_window_ms)
    """
    total_ms = len(audio)
    if total_ms <= 0:
        return 0, 0, 0

    lead_ms = detect_leading_silence(audio, silence_threshold=silence_threshold)
    trail_ms = detect_leading_silence(
        audio.reverse(), silence_threshold=silence_threshold
    )

    middle_start = min(lead_ms, total_ms)
    middle_end = max(middle_start, total_ms - trail_ms)
    middle_window_ms = max(0, middle_end - middle_start)
    if middle_window_ms <= 0:
        return 0, 0, 0

    middle = audio[middle_start:middle_end]
    nonsilent_ranges = detect_nonsilent(
        middle,
        min_silence_len=10,
        silence_thresh=silence_threshold,
        seek_step=10,
    )

    if not nonsilent_ranges:
        return middle_window_ms, middle_window_ms, middle_window_ms

    speech_ms = sum(max(0, end - start) for start, end in nonsilent_ranges)
    middle_silence_ms = max(0, middle_window_ms - speech_ms)

    max_middle_gap_ms = 0
    cursor = 0
    for start, end in nonsilent_ranges:
        gap = max(0, start - cursor)
        max_middle_gap_ms = max(max_middle_gap_ms, gap)
        cursor = max(cursor, end)
    max_middle_gap_ms = max(max_middle_gap_ms, max(0, middle_window_ms - cursor))

    return middle_silence_ms, max_middle_gap_ms, middle_window_ms


def load_audio(audio_path: str, sampling_rate: int):
    """
    Load the waveform with torchaudio and resampling if needed.

    Parameters:
        audio_path: path of the audio.
        sampling_rate: target sampling rate.

    Returns:
        Loaded prompt waveform with target sampling rate,
        PyTorch tensor of shape (1, T)
    """
    try:
        waveform, prompt_sampling_rate = torchaudio.load(audio_path)
    except (RuntimeError, OSError):
        # Fallback via pydub+ffmpeg for formats torchaudio can't handle
        aseg = AudioSegment.from_file(audio_path)
        audio_data = np.array(aseg.get_array_of_samples()).astype(np.float32) / 32768.0
        if aseg.channels == 1:
            waveform = torch.from_numpy(audio_data).unsqueeze(0)
        else:
            waveform = torch.from_numpy(audio_data.reshape(-1, aseg.channels).T)
        prompt_sampling_rate = aseg.frame_rate

    if prompt_sampling_rate != sampling_rate:
        waveform = torchaudio.functional.resample(
            waveform,
            orig_freq=prompt_sampling_rate,
            new_freq=sampling_rate,
        )
    if waveform.shape[0] > 1:
        waveform = torch.mean(waveform, dim=0, keepdim=True)

    return waveform


def remove_silence(
    audio: torch.Tensor,
    sampling_rate: int,
    mid_sil: int = 1000,
    lead_sil: int = 1000,
    trail_sil: int = 1000,
):
    """
    Remove middle silences longer than mid_sil ms, and edge silences longer than edge_sil ms

    Parameters:
        audio: PyTorch tensor with shape (C, T).
        sampling_rate: sampling rate of the audio.
        mid_sil: the duration of silences in the middle of audio to be removed in ms.
            if mid_sil <= 0, no middle silence will be removed.
        edge_sil: the duration of silences in the edge of audio to be removed in ms.
        trail_sil: the duration of added trailing silence in ms.

    Returns:
        PyTorch tensor with shape (C, T), where C is number of channels
            and T is number of audio samples
    """
    input_ms = _tensor_duration_ms(audio, sampling_rate)
    silence_threshold = _silence_threshold_db()

    # Load audio file
    wave = tensor_to_audiosegment(audio, sampling_rate)
    wave_before_ms = len(wave)
    edge_before_lead_ms = detect_leading_silence(
        wave, silence_threshold=silence_threshold
    )
    edge_before_trail_ms = detect_leading_silence(
        wave.reverse(), silence_threshold=silence_threshold
    )
    middle_before_ms, middle_max_gap_before_ms, middle_window_before_ms = (
        _middle_silence_stats(wave, silence_threshold)
    )

    mid_removed_estimate_ms = 0
    max_middle_gap_ms = 0

    mid_mode = "disabled"
    mid_threshold = abs(mid_sil)
    if mid_threshold > 0:
        # Estimate how much long middle silence could be reduced.
        nonsilent_ranges = detect_nonsilent(
            wave,
            min_silence_len=mid_threshold,
            silence_thresh=silence_threshold,
            seek_step=10,
        )
        if nonsilent_ranges:
            keep_between_chunks = max(0, mid_threshold // 2)
            for i in range(1, len(nonsilent_ranges)):
                prev_end = nonsilent_ranges[i - 1][1]
                current_start = nonsilent_ranges[i][0]
                gap = max(0, current_start - prev_end)
                max_middle_gap_ms = max(max_middle_gap_ms, gap)
                mid_removed_estimate_ms += max(0, gap - keep_between_chunks)

        if mid_sil > 0:
            mid_mode = "remove"
            # Split audio using silences longer than mid_sil
            non_silent_segs = split_on_silence(
                wave,
                min_silence_len=mid_threshold,
                silence_thresh=silence_threshold,
                # Keep at most ~mid_threshold total silence between concatenated chunks
                keep_silence=max(0, mid_threshold // 2),
                seek_step=10,
            )

            # Concatenate all non-silent segments
            wave = AudioSegment.silent(duration=0)
            for seg in non_silent_segs:
                wave += seg

            # If split_on_silence returns nothing (e.g., fully silent input), preserve original.
            if len(wave) == 0 and wave_before_ms > 0:
                wave = tensor_to_audiosegment(audio, sampling_rate)
        else:
            # Detect-only mode for middle pauses: collect stats but keep waveform unchanged.
            mid_mode = "detect-only"

    # Remove silence longer than 0.1 seconds in the begining and ending of wave
    wave = remove_silence_edges(wave, lead_sil, trail_sil, silence_threshold)

    wave_after_ms = len(wave)
    edge_after_lead_ms = detect_leading_silence(
        wave, silence_threshold=silence_threshold
    )
    edge_after_trail_ms = detect_leading_silence(
        wave.reverse(), silence_threshold=silence_threshold
    )
    middle_after_ms, middle_max_gap_after_ms, middle_window_after_ms = (
        _middle_silence_stats(wave, silence_threshold)
    )

    total_removed_ms = max(0, wave_before_ms - wave_after_ms)
    _log_audio_debug(
        "remove_silence "
        f"input_ms={input_ms:.1f} before_ms={wave_before_ms} after_ms={wave_after_ms} "
        f"removed_ms={total_removed_ms} "
        f"mid_removed_estimate_ms={mid_removed_estimate_ms} "
        f"max_middle_gap_ms={max_middle_gap_ms} "
        f"mid_mode={mid_mode} "
        f"middle_silence_ms(before={middle_before_ms}, after={middle_after_ms}) "
        f"middle_window_ms(before={middle_window_before_ms}, after={middle_window_after_ms}) "
        f"middle_max_gap_ms(before={middle_max_gap_before_ms}, after={middle_max_gap_after_ms}) "
        f"lead_silence_ms(before={edge_before_lead_ms}, after={edge_after_lead_ms}, cap={lead_sil}) "
        f"trail_silence_ms(before={edge_before_trail_ms}, after={edge_after_trail_ms}, cap={trail_sil}) "
        f"mid_cap_ms={mid_threshold} "
        f"silence_threshold_db={silence_threshold}"
    )

    # Convert to PyTorch tensor
    return audiosegment_to_tensor(wave)


def remove_silence_edges(
    audio: AudioSegment,
    lead_sil: int = 1000,
    trail_sil: int = 1000,
    silence_threshold: float = -60,
):
    """
    Remove edge silences longer than `keep_silence` ms.

    Parameters:
        audio: an AudioSegment object.
        keep_silence: kept silence in the edge.
        only_edge: If true, only remove edge silences.
        silence_threshold: the threshold of silence.

    Returns:
        An AudioSegment object
    """
    original_len_ms = len(audio)
    original_lead_ms = detect_leading_silence(audio, silence_threshold=silence_threshold)
    original_trail_ms = detect_leading_silence(
        audio.reverse(), silence_threshold=silence_threshold
    )

    # Remove heading silence
    start_idx = detect_leading_silence(audio, silence_threshold=silence_threshold)
    start_idx = max(0, start_idx - lead_sil)
    audio = audio[start_idx:]

    # Remove trailing silence
    audio = audio.reverse()
    start_idx = detect_leading_silence(audio, silence_threshold=silence_threshold)
    start_idx = max(0, start_idx - trail_sil)
    audio = audio[start_idx:]
    audio = audio.reverse()

    final_len_ms = len(audio)
    final_lead_ms = detect_leading_silence(audio, silence_threshold=silence_threshold)
    final_trail_ms = detect_leading_silence(
        audio.reverse(), silence_threshold=silence_threshold
    )

    _log_audio_debug(
        "remove_silence_edges "
        f"len_ms(before={original_len_ms}, after={final_len_ms}, removed={max(0, original_len_ms - final_len_ms)}) "
        f"lead_ms(before={original_lead_ms}, after={final_lead_ms}, cap={lead_sil}) "
        f"trail_ms(before={original_trail_ms}, after={final_trail_ms}, cap={trail_sil}) "
        f"threshold_db={silence_threshold}"
    )

    return audio


def audiosegment_to_tensor(aseg):
    """
    Convert a pydub.AudioSegment to PyTorch audio tensor
    """
    audio_data = np.array(aseg.get_array_of_samples())

    # Convert to float32 and normalize to [-1, 1] range
    audio_data = audio_data.astype(np.float32) / 32768.0

    # Handle channels
    if aseg.channels == 1:
        # Mono channel: add channel dimension (T) -> (1, T)
        tensor_data = torch.from_numpy(audio_data).unsqueeze(0)
    else:
        # Multi-channel: reshape to (C, T)
        tensor_data = torch.from_numpy(audio_data.reshape(-1, aseg.channels).T)

    return tensor_data


def tensor_to_audiosegment(tensor, sample_rate):
    """
    Convert a PyTorch audio tensor to pydub.AudioSegment

    Parameters:
        tensor: Tensor with shape (C, T), where C is the number of channels
            and T is the time steps
        sample_rate: Audio sample rate
    """
    # Convert tensor to numpy array
    assert isinstance(tensor, torch.Tensor)
    audio_np = tensor.cpu().numpy()

    # Convert to int16 type (common format for pydub)
    # Assumes tensor values are in [-1, 1] range as floating point
    audio_np = (audio_np * 32768.0).clip(-32768, 32767).astype(np.int16)

    # Convert to byte stream
    # For multi-channel audio, pydub requires interleaved format
    # (e.g., left-right-left-right)
    if audio_np.shape[0] > 1:
        # Convert to interleaved format
        audio_np = audio_np.transpose(1, 0).flatten()
    audio_bytes = audio_np.tobytes()

    # Create AudioSegment
    audio_segment = AudioSegment(
        data=audio_bytes,
        sample_width=2,
        frame_rate=sample_rate,
        channels=tensor.shape[0],
    )

    return audio_segment


def fade_and_pad_audio(
    audio: torch.Tensor,
    pad_duration: float = 0.0,
    fade_duration: float = 0.0,
    sample_rate: int = 24000,
) -> torch.Tensor:
    """
    Applies a smooth fade-in and fade-out to the audio, and then pads both sides
    with pure silence to prevent abrupt starts and ends (clicks/pops).

    Args:
        audio: PyTorch tensor of shape (C, T) containing audio data.
        pad_duration: Duration of pure silence to add to each end (in seconds).
        fade_duration: Duration of the fade-in/out curve (in seconds).
        sample_rate: Audio sampling rate.

    Returns:
        Processed sequence tensor with shape (C, T_new)
    """
    if audio.shape[-1] == 0:
        _log_audio_debug("fade_and_pad_audio input is empty, skipping")
        return audio

    input_ms = _tensor_duration_ms(audio, sample_rate)
    fade_samples = int(fade_duration * sample_rate)
    pad_samples = int(pad_duration * sample_rate)

    processed = audio.clone()

    if fade_samples > 0:
        k = min(fade_samples, processed.shape[-1] // 2)

        if k > 0:
            fade_in = torch.linspace(
                0, 1, k, device=processed.device, dtype=processed.dtype
            )[None, :]
            processed[..., :k] = processed[..., :k] * fade_in

            fade_out = torch.linspace(
                1, 0, k, device=processed.device, dtype=processed.dtype
            )[None, :]
            processed[..., -k:] = processed[..., -k:] * fade_out

    if pad_samples > 0:
        silence = torch.zeros(
            (processed.shape[0], pad_samples),
            dtype=processed.dtype,
            device=processed.device,
        )
        processed = torch.cat([silence, processed, silence], dim=-1)

    output_ms = _tensor_duration_ms(processed, sample_rate)
    _log_audio_debug(
        "fade_and_pad_audio "
        f"input_ms={input_ms:.1f} output_ms={output_ms:.1f} "
        f"added_pad_ms={max(0.0, output_ms - input_ms):.1f} "
        f"pad_duration_s={pad_duration} fade_duration_s={fade_duration} "
        f"fade_samples={fade_samples} pad_samples={pad_samples}"
    )

    return processed


def trim_long_audio(
    audio: torch.Tensor,
    sampling_rate: int,
    max_duration: float = 15.0,
    min_duration: float = 3.0,
    trim_threshold: float = 20.0,
) -> torch.Tensor:
    """Return audio unchanged (trimming disabled).

    Parameters are kept for backward compatibility with existing call sites.
    """
    input_ms = _tensor_duration_ms(audio, sampling_rate)
    _log_audio_debug(
        "trim_long_audio disabled "
        f"input_ms={input_ms:.1f} output_ms={input_ms:.1f} removed_ms=0.0 "
        f"max_duration_s={max_duration} min_duration_s={min_duration} trim_threshold_s={trim_threshold}"
    )
    _ = (sampling_rate, max_duration, min_duration, trim_threshold)
    return audio


def cross_fade_chunks(
    chunks: list[torch.Tensor],
    sample_rate: int,
    silence_duration: float = 0.0,
) -> torch.Tensor:
    """Concatenate audio chunks with a short silence gap and fade at boundaries.

    Each boundary is structured as: fade-out tail → silence buffer → fade-in head.
    This avoids click artifacts from direct concatenation or overlapping mismatch.

    Args:
        chunks: List of audio tensors, each (C, T).
        sample_rate: Audio sample rate.
        silence_duration: Total silence gap duration in seconds.

    Returns:
        Merged audio tensor (C, T_total).
    """
    if len(chunks) == 1:
        _log_audio_debug(
            f"cross_fade_chunks single chunk, unchanged, duration_ms={_tensor_duration_ms(chunks[0], sample_rate):.1f}"
        )
        return chunks[0]

    input_total_ms = sum(_tensor_duration_ms(chunk, sample_rate) for chunk in chunks)

    total_n = int(silence_duration * sample_rate)
    fade_n = total_n // 3
    silence_n = fade_n  # middle silent gap
    merged = chunks[0].clone()

    for chunk in chunks[1:]:
        dev, dt = merged.device, merged.dtype
        parts = [merged]

        # Fade out tail of current merged audio
        fout_n = min(fade_n, merged.size(-1))
        if fout_n > 0:
            w_out = torch.linspace(1, 0, fout_n, device=dev, dtype=dt)[None, :]
            parts[-1][..., -fout_n:] = parts[-1][..., -fout_n:] * w_out

        # Silent buffer between chunks
        parts.append(torch.zeros(chunks[0].shape[0], silence_n, device=dev, dtype=dt))

        # Fade in head of next chunk
        fade_in = chunk.clone()
        fin_n = min(fade_n, fade_in.size(-1))
        if fin_n > 0:
            w_in = torch.linspace(0, 1, fin_n, device=dev, dtype=dt)[None, :]
            fade_in[..., :fin_n] = fade_in[..., :fin_n] * w_in

        parts.append(fade_in)
        merged = torch.cat(parts, dim=-1)

    output_ms = _tensor_duration_ms(merged, sample_rate)
    _log_audio_debug(
        "cross_fade_chunks "
        f"chunks={len(chunks)} input_total_ms={input_total_ms:.1f} output_ms={output_ms:.1f} "
        f"added_gap_ms={max(0.0, output_ms - input_total_ms):.1f} "
        f"silence_duration_s={silence_duration}"
    )

    return merged
